-- Custom datasource rules
INSERT OR IGNORE INTO renovate_rules (rule_id, category, title, description, dont_config, do_config, severity) VALUES
('CDS-1', 'custom_datasources', 'Use regex managers for non-standard tools', 'Tools without native Renovate support need customManagers with regex to track versions.', '{}', '{"customManagers": [{"customType": "regex", "fileMatch": ["Makefile$", "\\.sh$"], "matchStrings": ["TOOL_VERSION\\s*[:=]\\s*\"?(?<currentValue>[^\"\\s]+)\"?"], "depNameTemplate": "example/tool", "datasourceTemplate": "github-releases"}]}', 'INFO'),
('CDS-2', 'custom_datasources', 'Set extractVersion for release tags', 'Many GitHub releases use v-prefixed tags. extractVersionTemplate strips the prefix for clean matching.', '{}', '{"customManagers": [{"customType": "regex", "matchStrings": ["VERSION=(?<currentValue>.+)"], "extractVersionTemplate": "^v(?<version>.+)$", "datasourceTemplate": "github-releases"}]}', 'INFO'),
('CDS-3', 'custom_datasources', 'Configure versioningTemplate', 'Non-semver tools need explicit versioning: loose, semver-coerced, or regex patterns.', '{}', '{"customManagers": [{"customType": "regex", "matchStrings": ["VERSION=(?<currentValue>.+)"], "versioningTemplate": "semver-coerced", "datasourceTemplate": "github-releases"}]}', 'INFO'),
('CDS-4', 'custom_datasources', 'Map depName for custom registries', 'Custom registry tools need explicit depName and packageName for correct version lookup.', '{}', '{"customManagers": [{"customType": "regex", "matchStrings": ["WIZ_CLI_VERSION=(?<currentValue>.+)"], "depNameTemplate": "wizcli", "packageNameTemplate": "https://downloads.wiz.io/wizcli/releases", "datasourceTemplate": "custom.wiz-cli"}]}', 'INFO'),
('CDS-5', 'custom_datasources', 'Define custom datasource for Wiz CLI', 'Tools like Wiz CLI publish releases outside standard registries and need custom datasource definitions.', '{}', '{"customDatasources": {"wiz-cli": {"defaultRegistryUrlTemplate": "https://downloads.wiz.io/wizcli/releases", "transformTemplates": ["{ \"releases\": $map($, function($v) { { \"version\": $v.tag_name } }) }"]}}  }', 'INFO'),
('CDS-6', 'custom_datasources', 'Use fileMatch to scope regex managers', 'Regex managers should be scoped to specific files to avoid false matches across the repo.', '{"customManagers": [{"customType": "regex", "fileMatch": [".*"]}]}', '{"customManagers": [{"customType": "regex", "fileMatch": ["Makefile$", "scripts/install\\.sh$"]}]}', 'WARN');
